import React from 'react';
import {
  Calendar,
  Bot,
  MessageSquare,
  Activity,
  Shield,
  Clock,
  Building2,
  ChevronRight,
  Sparkles,
} from 'lucide-react';

const FEATURES = [
  { 
    icon: Calendar, 
    label: 'Smart Appointment Booking', 
    desc: 'Book visits instantly with real-time doctor availability' 
  },
  { 
    icon: Bot, 
    label: 'AI-Powered Diagnosis', 
    desc: 'Get instant health insights powered by advanced AI' 
  },
  { 
    icon: MessageSquare, 
    label: 'Direct Doctor Messaging', 
    desc: '24/7 consultation access with your healthcare providers' 
  },
  { 
    icon: Activity, 
    label: 'Health Tracking & Records', 
    desc: 'Complete medical history and health metrics tracking' 
  },
  { 
    icon: Shield, 
    label: 'Secure & Private', 
    desc: 'HIPAA compliant platform with end-to-end encryption' 
  },
  { 
    icon: Clock, 
    label: '24/7 Access', 
    desc: 'Available anytime, anywhere on any device' 
  },
];

export default function LandingPage({ onSignIn, onSignUp }) {
  return (
    <div style={{ minHeight: '100vh', background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', position: 'relative', overflow: 'hidden' }}>
      {/* Animated Background Elements */}
      <div style={{ position: 'absolute', top: 0, left: 0, right: 0, bottom: 0, overflow: 'hidden' }}>
        <div style={{
          position: 'absolute',
          top: '-50%',
          left: '-50%',
          width: '200%',
          height: '200%',
          background: 'radial-gradient(circle, rgba(255,255,255,0.1) 1px, transparent 1px)',
          backgroundSize: '50px 50px',
          animation: 'drift 20s linear infinite',
        }} />
        
        {/* Floating orbs */}
        <div style={{
          position: 'absolute',
          top: '10%',
          left: '10%',
          width: 300,
          height: 300,
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(255,255,255,0.15), transparent)',
          filter: 'blur(40px)',
          animation: 'float 6s ease-in-out infinite',
        }} />
        <div style={{
          position: 'absolute',
          bottom: '10%',
          right: '10%',
          width: 300,
          height: 300,
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(255,255,255,0.1), transparent)',
          filter: 'blur(40px)',
          animation: 'float 8s ease-in-out infinite 1s',
        }} />
      </div>

      <style>{`
        @keyframes drift {
          0% { transform: translate(0, 0); }
          50% { transform: translate(50px, 50px); }
          100% { transform: translate(0, 0); }
        }
        
        @keyframes float {
          0%, 100% { transform: translateY(0px) scale(1); }
          50% { transform: translateY(-30px) scale(1.05); }
        }

        @keyframes fadeInUp {
          from {
            opacity: 0;
            transform: translateY(30px);
          }
          to {
            opacity: 1;
            transform: translateY(0);
          }
        }

        @keyframes slideInRight {
          from {
            opacity: 0;
            transform: translateX(30px);
          }
          to {
            opacity: 1;
            transform: translateX(0);
          }
        }

        @keyframes pulse {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.05); }
        }

        @keyframes glow {
          0%, 100% { box-shadow: 0 0 20px rgba(102, 126, 234, 0.4); }
          50% { box-shadow: 0 0 40px rgba(102, 126, 234, 0.8); }
        }

        @keyframes slideUp {
          from { transform: translateY(20px); opacity: 0; }
          to { transform: translateY(0); opacity: 1; }
        }

        @keyframes bounce {
          0%, 100% { transform: translateY(0); }
          50% { transform: translateY(-10px); }
        }

        @keyframes shimmer {
          0% { background-position: -1000px 0; }
          100% { background-position: 1000px 0; }
        }
      `}</style>

      {/* Content Container */}
      <div style={{ position: 'relative', zIndex: 1 }}>
        {/* Header */}
        <div style={{
          padding: '20px 24px',
          display: 'flex',
          alignItems: 'center',
          gap: 12,
          color: 'white',
        }}>
          <Building2 size={32} strokeWidth={1.5} />
          <div>
            <div style={{ fontSize: 20, fontWeight: 700 }}>Health Easy Portal</div>
            <div style={{ fontSize: 12, opacity: 0.9 }}>Your all-in-one health management platform</div>
          </div>
        </div>

        {/* Hero Section */}
        <div style={{
          padding: '60px 24px 40px',
          textAlign: 'center',
          color: 'white',
          maxWidth: 800,
          margin: '0 auto',
        }}>
          <div style={{
            fontSize: 48,
            fontWeight: 800,
            marginBottom: 20,
            lineHeight: 1.2,
            animation: 'fadeInUp 0.8s ease-out',
          }}>
            Transform Your <br /> Healthcare Experience
          </div>
          <p style={{
            fontSize: 18,
            opacity: 0.95,
            marginBottom: 32,
            animation: 'fadeInUp 0.8s ease-out 0.1s both',
          }}>
            Connect with healthcare professionals, track your health, and get AI-powered insights—all in one secure platform.
          </p>
        </div>

        {/* Features Grid */}
        <div style={{
          padding: '40px 24px',
          maxWidth: 1100,
          margin: '0 auto',
        }}>
          <div style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 24,
            marginBottom: 60,
          }}>
            {FEATURES.map((feature, idx) => (
              <div
                key={idx}
                style={{
                  background: 'rgba(255, 255, 255, 0.95)',
                  borderRadius: 16,
                  padding: 28,
                  boxShadow: '0 10px 30px rgba(0, 0, 0, 0.2)',
                  transition: 'all 0.3s ease',
                  cursor: 'pointer',
                  animation: `fadeInUp 0.6s ease-out ${0.1 * idx}s both`,
                  backdropFilter: 'blur(10px)',
                }}
                onMouseOver={e => {
                  e.currentTarget.style.transform = 'translateY(-10px)';
                  e.currentTarget.style.boxShadow = '0 20px 40px rgba(0, 0, 0, 0.3)';
                }}
                onMouseOut={e => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 10px 30px rgba(0, 0, 0, 0.2)';
                }}
              >
                <div style={{
                  width: 56,
                  height: 56,
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  borderRadius: 12,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  marginBottom: 16,
                }}>
                  <feature.icon size={28} color="white" strokeWidth={1.5} />
                </div>
                <h3 style={{
                  fontSize: 18,
                  fontWeight: 700,
                  marginBottom: 8,
                  color: '#1a1a2e',
                }}>
                  {feature.label}
                </h3>
                <p style={{
                  fontSize: 14,
                  color: '#666',
                  lineHeight: 1.6,
                }}>
                  {feature.desc}
                </p>
              </div>
            ))}
          </div>

          {/* CTA Buttons */}
          <div style={{
            display: 'flex',
            gap: 16,
            justifyContent: 'center',
            flexWrap: 'wrap',
            padding: '40px 0',
            animation: 'slideInRight 0.8s ease-out 0.6s both',
          }}>
            <button
              onClick={onSignIn}
              style={{
                padding: '16px 48px',
                background: 'white',
                color: '#667eea',
                border: 'none',
                borderRadius: 12,
                fontSize: 16,
                fontWeight: 700,
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                transition: 'all 0.3s ease',
                boxShadow: '0 10px 25px rgba(0, 0, 0, 0.2)',
              }}
              onMouseOver={e => {
                e.currentTarget.style.transform = 'scale(1.05)';
                e.currentTarget.style.boxShadow = '0 15px 35px rgba(0, 0, 0, 0.3)';
              }}
              onMouseOut={e => {
                e.currentTarget.style.transform = 'scale(1)';
                e.currentTarget.style.boxShadow = '0 10px 25px rgba(0, 0, 0, 0.2)';
              }}
            >
              Sign In
              <ChevronRight size={18} strokeWidth={2} />
            </button>

            <button
              onClick={onSignUp}
              style={{
                padding: '16px 48px',
                background: 'transparent',
                color: 'white',
                border: '2px solid white',
                borderRadius: 12,
                fontSize: 16,
                fontWeight: 700,
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                transition: 'all 0.3s ease',
              }}
              onMouseOver={e => {
                e.currentTarget.style.background = 'rgba(255, 255, 255, 0.15)';
                e.currentTarget.style.transform = 'scale(1.05)';
              }}
              onMouseOut={e => {
                e.currentTarget.style.background = 'transparent';
                e.currentTarget.style.transform = 'scale(1)';
              }}
            >
              Create Account
              <ChevronRight size={18} strokeWidth={2} />
            </button>
          </div>
        </div>

        {/* Footer */}
        <div style={{
          padding: '20px 24px',
          textAlign: 'center',
          color: 'rgba(255, 255, 255, 0.8)',
          fontSize: 12,
          borderTop: '1px solid rgba(255, 255, 255, 0.1)',
          marginTop: 40,
        }}>
          <p>🔒 Secure • HIPAA Compliant • Available 24/7</p>
        </div>
      </div>
